#!/bin/bash

# Database credentials
DB_HOST="localhost"
DB_USER="backup_user"
DB_PASS="BackupPass123"

# List of databases to backup
DB_LIST="database1 database2 database3"

# Iterate through each database
for db in $DB_LIST; do
    # Create a backup filename
    BACKUP_FILE="/path/to/backup/$db.sql"

    # Create the dump
    mysql -h $DB_HOST -u $DB_USER -p$DB_PASS $db > $BACKUP_FILE
done